def assess(record: dict) -> str:
    required = {'metric', 'expected_top', 'query', 'version', 'docs', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (min(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) == record["expected_top"])
    return "PASS" if meets else 'REJECT_EMBEDDING_RANK'

valid = {'case_id': 'CASO-PUN-048-1A', 'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}
